<?php
// Define the base directory where files are stored.
// It's highly recommended to place this directory OUTSIDE of the web root
// to prevent direct access, but for this example, we'll assume it's
// a subdirectory named 'uploads' relative to the script's location.
define('UPLOAD_DIR', __DIR__ . DIRECTORY_SEPARATOR . 'uploads');

// Ensure the uploads directory exists and is writable (for file uploads, not strictly for downloads)
// For downloads, it just needs to be readable.
if (!is_dir(UPLOAD_DIR)) {
    // You might want to create it or log an error if it's missing
    // For this script, we'll just let the file_exists check handle it.
}

// 1. Check if a file name was provided in the GET request
if (!isset($_GET['file']) || empty($_GET['file'])) {
    header("HTTP/1.0 400 Bad Request");
    echo "Error: No file specified for download.";
    exit;
}

$requestedFile = $_GET['file'];

// 2. Sanitize the requested file path to prevent directory traversal attacks.
// Remove any '..' segments and null bytes.
$requestedFile = str_replace(['../', './', "\0"], '', $requestedFile);
// Remove leading slashes/backslashes to ensure it's relative to UPLOAD_DIR
$requestedFile = ltrim($requestedFile, '/\\');

// 3. Construct the full absolute path to the requested file.
$filePath = UPLOAD_DIR . DIRECTORY_SEPARATOR . $requestedFile;

// 4. Validate the file path and existence.
// Use realpath to resolve any symbolic links and get the canonicalized absolute path.
$realFilePath = realpath($filePath);
$realUploadDir = realpath(UPLOAD_DIR);

// Check multiple conditions for security and validity:
// a) realpath() must not return false (meaning the file/path exists).
// b) The path must point to an actual file (not a directory).
// c) The file must be readable.
// d) Crucially, the real path of the requested file must start with the real path of the upload directory.
//    This prevents directory traversal even if some sanitization was bypassed.
if (
    $realFilePath === false ||
    !is_file($realFilePath) ||
