    header("HTTP/1.0 404 Not Found");
    echo "Error: File not found or access denied.";
    exit;
}

// 5. Determine the MIME type of the file.
// This helps the browser handle the file correctly (e.g., open PDF in browser, download ZIP).
$finfo = finfo_open(FILEINFO_MIME_TYPE);
